#usda 1.0
(
    defaultPrim = "Materials"
)

def Scope "Materials"
{
    def Material "WoodMat"
    {
        token outputs:surface.connect = </Materials/WoodMat/Surface.outputs:surface>

        def Shader "Surface"
        {
            uniform token info:id = "UsdPreviewSurface"
            float3 inputs:diffuseColor.connect = </Materials/WoodMat/WoodTex.outputs:rgb>
            float inputs:metallic = 0
            float inputs:roughness = 0.7
            token outputs:surface
        }

        def Shader "WoodTex"
        {
            uniform token info:id = "UsdUVTexture"
            asset inputs:file = @wood_diffuse.png@
            float2 inputs:st.connect = </Materials/WoodMat/UVReader.outputs:result>
            float3 outputs:rgb
        }

        def Shader "UVReader"
        {
            uniform token info:id = "UsdPrimvarReader_float2"
            token inputs:varname = "st"
            float2 outputs:result
        }
    }

    def Material "MetalMat"
    {
        token outputs:surface.connect = </Materials/MetalMat/Surface.outputs:surface>

        def Shader "Surface"
        {
            uniform token info:id = "UsdPreviewSurface"
            float3 inputs:diffuseColor = (0.8, 0.8, 0.85)
            float inputs:metallic = 1
            float inputs:roughness = 0.2
            token outputs:surface
        }
    }
}

def "Geometry"
{
    def Mesh "Table"
    {
        int[] faceVertexCounts = [4]
        int[] faceVertexIndices = [0, 1, 2, 3]
        rel material:binding = </Materials/MetalMat>
        point3f[] points = [(-1, 0, -1), (1, 0, -1), (1, 0, 1), (-1, 0, 1)]

        def GeomSubset "top_face" (
            prepend apiSchemas = ["MaterialBindingAPI"]
        )
        {
            uniform token elementType = "face"
            int[] indices = [0]
            rel material:binding = </Materials/WoodMat>
        }
    }
}
